---@class LBatchTask
local LBatchTask = LxClass("LBatchTask", nil)

local BatchTaskState = {
    Stop = 0,
    Running = 1
}

local InvokeCallback = function(cbFunc, cbObj, ...)
    if cbObj then
        cbFunc(cbObj, ...)
    else
        cbFunc(...)
    end
end


function LBatchTask:Initialize()
    self._taskState = BatchTaskState.Stop
end

function LBatchTask:InitBatchTask(cbText, cbProgress, execOK, cbObj)
    if self._taskState == BatchTaskState.Stop then
        self._cbObj = cbObj
        self._loadOk = execOK
        self._cbText = cbText
        self._cbProgress = cbProgress
        self._taskList = {}
    end
end

function LBatchTask:AddBatchTask(name, desc, execOK, execObj)
    if self._taskState == BatchTaskState.Stop then
        local task = {
            name = name,
            desc = desc,
            execOK = execOK,
            execObj = execObj
        }
        table.insert(self._taskList, task)
    end
end

function LBatchTask:StartBatchTask()
    if self._taskState == BatchTaskState.Stop then
        self._refIndex = 0
        self._taskState = BatchTaskState.Running
        self._refCount = #self._taskList
        self:NextBatchTask()
    end
end

function LBatchTask:NextBatchTask()
    if self._refIndex >= self._refCount then
        if LOG_INFO_ENABLED then
            printInfoN2("BatchTask", "Finished Task !!!");
        end
        self:StopBatchTask()
        return
    end
    local task = table.remove(self._taskList, 1)
    if task ~= nil then
        if LOG_INFO_ENABLED then
            printInfoN2("BatchTask", string.format("New Task---->>> name:%s, desc:>%s", tostring(task.name), tostring(task.desc)));
        end
        if self._cbText ~= nil then
            InvokeCallback(self._cbText, self._cbObj, task.desc)
        end
        if task.execOK ~= nil then
            InvokeCallback(task.execOK, task.execObj, self.OnBatchTaskOK, self)
            task.execOK = nil
            task.execObj = nil
        end
    end
end

function LBatchTask:StopBatchTask()
    local loadOk = self._loadOk
    local cbObj = self._cbObj
    self._loadOk = nil
    self._cbText = nil
    self._cbProgress = nil
    self._cbObj = nil
    if self._taskList then
        for k,v in ipairs(self._taskList) do
            v.execOK = nil
            v.execObj = nil
        end
        self._taskList = nil
    end
    self._taskState = BatchTaskState.Stop

    if loadOk ~= nil then
        InvokeCallback(loadOk, cbObj)
    end
end

function LBatchTask:OnBatchTaskOK()
    self._refIndex = self._refIndex + 1
    if self._cbProgress ~= nil then
        InvokeCallback(self._cbProgress, self._cbObj, self._refIndex, self._refCount)
    end
    self:NextBatchTask()
end

return LBatchTask
